87	
88	    it("should reimburse high enchantment damage at 50%", () => {
89	      const policy = { items: [{ type: "sword", damage: 50, enchantment: 8 }], coverage: 100 };
90	      const damage = { type: "sword", amount: 250 };
91	      expect(processClaim(policy, damage)).toBe(300);
92	    });
93	    it("should apply dragon material full reimbursement", () => {
94	      const policy = { items: [{ type: "sword", damage: 50, dragonMaterial: true }], coverage: 100 };
95	      const damage = { type: "sword", amount: 150 };
96	      expect(processClaim(policy, damage)).toBe(150);
