105	      const result = processMultipleDamages(policy, damages);
106	      expect(result).toBe(60); // (130-100) + (130-100) = 30 + 30 = 60
107	    });
108	    it.todo("should apply separate deductible for each damage event");
109	
110	    it("should reject claim for damage to item not in policy", () => {
111	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
112	      const damage = { type: "amulet", amount: 150 };
113	      expect(() => processClaim(policy, damage)).toThrow();
114	    });
115	    it("should reject claim with negative damage amount", () => {
116	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
117	      const damage = { type: "sword", amount: -50 };
118	      expect(() => processClaim(policy, damage)).toThrow();
119	    });
120	  });
121	});
